import{_ as e,o as r,c as o,ai as t}from"./chunks/framework.ampVZV4B.js";const k=JSON.parse('{"title":"03 做一个工具：读写 Markdown（本地知识库）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-2-agent/03-tool-readwrite-markdown.md","filePath":"ai/stage-2-agent/03-tool-readwrite-markdown.md"}'),l={name:"ai/stage-2-agent/03-tool-readwrite-markdown.md"};function i(n,a,d,s,_,c){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="_03-做一个工具-读写-markdown-本地知识库" tabindex="-1">03 做一个工具：读写 Markdown（本地知识库） <a class="header-anchor" href="#_03-做一个工具-读写-markdown-本地知识库" aria-label="Permalink to “03 做一个工具：读写 Markdown（本地知识库）”">​</a></h1><blockquote><p>目标：先把 Tools 做出来，再接 Agent。你只要实现“读/写 Markdown”两个能力就够了。</p></blockquote><h2 id="_1-工具清单-最小两件事" tabindex="-1">1）工具清单（最小两件事） <a class="header-anchor" href="#_1-工具清单-最小两件事" aria-label="Permalink to “1）工具清单（最小两件事）”">​</a></h2><ul><li><strong>read</strong>：给一个路径，读出 Markdown 文本</li><li><strong>write</strong>：给一个路径与内容，写入 Markdown 文件</li></ul><h2 id="_2-建议约束-避免写坏你的知识库" tabindex="-1">2）建议约束（避免写坏你的知识库） <a class="header-anchor" href="#_2-建议约束-避免写坏你的知识库" aria-label="Permalink to “2）建议约束（避免写坏你的知识库）”">​</a></h2><ul><li>只允许写到指定目录（例如 <code>generated/</code>）</li><li>写文件前做一次存在性检查（避免覆盖）</li><li>每次写入都记录日志：时间、路径、字数</li></ul><h2 id="_3-今日练习" tabindex="-1">3）今日练习 <a class="header-anchor" href="#_3-今日练习" aria-label="Permalink to “3）今日练习”">​</a></h2><ul><li>手写 <code>read_markdown()</code> / <code>write_markdown()</code> 两个函数</li><li>用它们做一次“读 → 写”的复制动作（不接 LLM）</li></ul>',8)])])}const m=e(l,[["render",i]]);export{k as __pageData,m as default};
